const config = $('Set YouTube research topic & API key').first().json;
const items = $input.first().json.items || [];
return items.map((item) => {
  const snippet = item.snippet || {};
  const videoId = item.id?.videoId || '';
  const title = snippet.title || 'Untitled Video';
  const channel = snippet.channelTitle || 'YouTube Channel';
  const publishedAt = snippet.publishedAt || new Date().toISOString();
  const description = snippet.description || '';
  const sourceUrl = videoId ? `https://www.youtube.com/watch?v=${videoId}` : 'https://www.youtube.com';
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `YouTube Video: ${title}`,
      sourceUrl,
      publishedAt,
      sourceName: 'YouTube Data API v3',
      sourceType: 'media',
      content: `YouTube video metadata for query '${config.searchQuery}'. Title: ${title}. Channel: ${channel}. Published: ${publishedAt}. Description snippet: ${description}. URL: ${sourceUrl}.` 
    }
  };
});
